import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const D=JSON.parse('{"title":"白色死神","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/白色死神.md","filePath":"4.资源分区/7.物品与装备/6.套装/白色死神.md"}'),b={name:"4.资源分区/7.物品与装备/6.套装/白色死神.md"};function o(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"白色死神",tabindex:"-1"},[n("白色死神 "),r("a",{class:"header-anchor",href:"#白色死神","aria-label":'Permalink to "白色死神"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),s('<h1 id="白色死神-1" tabindex="-1">白色死神 <a class="header-anchor" href="#白色死神-1" aria-label="Permalink to &quot;白色死神&quot;">​</a></h1><p>白色死神<br> 自然本质/科技本质</p><p>该套装下属武器、防具、技艺需一次性全部购买。</p><p>莫辛-纳甘步枪<br> 价格：D+500<br> 科技本质<br> 芬兰版的莫辛-纳甘步枪，作为一种旋转后拉式枪机、整体弹仓式供弹的手动操作步枪，该枪射击精度好、性能稳定。该版本似乎还经过了改装调整，使其性能非常接近狙击步枪的水准。</p><p>莫辛-纳甘步枪采用基础远程武器中的狙击枪模板，具有全部相关特性，在其基础上提升3L武器伤害。</p><p>风衣<br> 自然本质<br> 价格：D+500<br> 雪一样白的白色伪装服。</p><p>作为轻甲提供5/5的掩蔽防御，同时提供D级自然本质反侦测能力，穿戴者还会获得免疫不超过D级环境影响的效果。</p><p>白色死神<br> 前置：莫辛-纳甘步枪，风衣<br> 价格：D+1500<br> 动作：整轮动作<br> 消耗：3点意志力<br> 范围：见下<br> 持续：一场景<br> 描述：-<br> 效果：使用该技能后，薄雾渐渐升起，你的身影逐渐消失在从天空飘落的雪中，这视为以你为中心，半径【30+传奇决心*5】米的范围内的环境在次轮开始时变更为【永久冻土Ⅰ】 ，这是一个D级环境来源的效果影响。随后你可以进行一次基础规则中的潜行行为。</p><p>【永久冻土Ⅰ】：【永久冻土Ⅰ】会对影响范围内的单位产生以下的效果（个别效果也对范围外有效，见效果）：<br> 1.由于地面被大量冰雪覆盖，处于环境影响下的单位在移动时，需要进行一个DC为8的平衡检定，失败则会倒地。角色可以将自身移动速度减半以避免这一检定。</p><p>2.由于气温极低，受影响单位在这类环境下每连续活动1小时，就需要进行一个强韧豁免，DC为8，失败则承受差值点肢体残障点数，作用于每一个肢体。</p><p>3.由于暴风雪，受影响单位额外具有【冻寒能量易伤2】，身上的燃烧点数每轮会降低1点。</p><p>4.由于暴风雪，受影响单位处于区域内会减少150米视力感知范围至多减少至5米，进行的视觉侦测检定受到6DP的环境减值。<br> 区域外的受影响单位对环境区域的视觉感知范围减少150米，进行的视觉侦测检定受到6DP的环境减值。</p><p>幸运的子弹<br> 前置：白色死神<br> 分类：奇物（饰品位）<br> 价格：D+1000<br> 描述：“他曾在一场近战中被达姆弹击中下颚，子弹向上贯穿他的左脑。他被后方的士兵救起，该名士兵宣称：他将近一半的头部都不见了。数月之后，他奇迹般地复原了。”<br> 效果：你获得快速医疗1。你在使用白色死神技艺时，该技艺范围扩大到【50+传奇决心*5米】，并使【永久冻土Ⅰ】效果改为【永久冻土Ⅱ】，依旧视为D级环境来源的效果。</p><p>【永久冻土Ⅱ】：在永久冻土Ⅰ的基础上，受影响单位额外获得【电易伤1】、【火焰伤害抗力1】，以视觉进行的侦测行为减值提升到12DP，以听觉进行侦测的行为受到6DP环境减值，以视觉、听觉进行侦测定位时敏感范围再下降30米，这些效果只针对环境影响范围内。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const f=a(b,[["render",o]]);export{D as __pageData,f as default};
